package kotlinx.coroutines

import kotlin.coroutines.*
import kotlin.test.*

/**
 * Tests for CoroutineContext.isActive property.
 * This test verifies that isActive returns true for contexts without a Job,
 * which aligns with the behavior of CoroutineScope.isActive.
 */
class CoroutineContextIsActiveTest : TestBase() {

    @Test
    fun testIsActiveWithJob() = runTest {
        val job = Job()
        val context = job + CoroutineName("test")

        // Active job should return true
        assertTrue(context.isActive)
        assertTrue(job.isActive)

        // Cancel the job
        job.cancel()
        job.join()

        // Cancelled job should return false
        assertFalse(context.isActive)
        assertFalse(job.isActive)
    }

    @Test
    fun testIsActiveWithoutJob() = runTest {
        // Context without a Job should return true
        val context = CoroutineName("test") + Dispatchers.Default
        assertTrue(context.isActive, "Context without Job should be considered active")

        // Empty context should also return true
        assertTrue(EmptyCoroutineContext.isActive, "EmptyCoroutineContext should be considered active")
    }

    @Test
    fun testIsActiveInEmptyContext() = runTest {
        withEmptyContext {
            // Inside an empty context, isActive should return true
            assertTrue(coroutineContext.isActive, "Empty context should be considered active")
        }
    }

    @Test
    fun testIsActiveConsistencyWithCoroutineScope() = runTest {
        // Test that CoroutineContext.isActive and CoroutineScope.isActive behave consistently

        // For context with Job
        val jobContext = Job() + CoroutineName("test")
        val scope = CoroutineScope(jobContext)
        assertEquals(jobContext.isActive, scope.isActive, "Context and scope should have same isActive value")

        // For context without Job (CoroutineScope always adds a Job, so we test the underlying behavior)
        val noJobContext = CoroutineName("test")
        assertTrue(noJobContext.isActive, "Context without Job should be active")
    }

    @Test
    fun testIsActiveInSuspendMain() = runTest {
        // Simulates the scenario described in the issue:
        // non-kotlinx.coroutines entry points like suspend fun main or Ktor
        // where there might not be a Job in the context
        withEmptyContext {
            // This should not return false anymore, but true
            assertTrue(coroutineContext.isActive, "Should be active even without Job")

            // This pattern should work for cancellation checks
            var iterations = 0
            while (coroutineContext.isActive && iterations < 5) {
                iterations++
            }
            assertEquals(5, iterations, "Loop should complete all iterations")
        }
    }

    @Test
    fun testIsActiveWithCompletedJob() = runTest {
        val job = Job()
        val context = job + CoroutineName("test")

        assertTrue(context.isActive)

        // Complete the job
        job.complete()
        job.join()

        // Completed job should return false
        assertFalse(context.isActive)
    }

    @Test
    fun testIsActiveWithCancelledJob() = runTest {
        val job = Job()
        val context = job + CoroutineName("test")

        assertTrue(context.isActive)

        job.cancel()

        // Immediately after cancel, before join, it should still be false
        assertFalse(context.isActive)

        job.join()
        assertFalse(context.isActive)
    }

    @Test
    fun testIsActiveWithGlobalScope() = runTest {
        // GlobalScope has no Job, so it should return true
        @OptIn(DelicateCoroutinesApi::class)
        assertTrue(GlobalScope.coroutineContext.isActive, "GlobalScope context should be active")
    }

    @Test
    fun testIsActiveWithNonCancellable() = runTest {
        // NonCancellable is always active
        assertTrue(NonCancellable.isActive)
        assertTrue((CoroutineName("test") + NonCancellable).isActive)
    }
}
"}

